1	// D14 — Claim extraction submit task (Batch API path)
2	//
3	// Cron: every 4 hours, same as the sync claim-extraction worker. Bails when
4	// settings.extraction_dispatch_mode !== 'batch'. The sync worker has a
5	// mirror-image bail when the flag IS 'batch', so the two paths never both
6	// process the same messages.
7	//
8	// Flow:
9	//   1. Read the flag — bail if not 'batch'
10	//   2. Resolve the extraction route + check its adapter supports batch
11	//   3. Pull pending user messages (BATCH_SIZE), mark them 'processing'
12	//   4. Group into 60-minute conversation segments
13	//   5. For each segment: compile the prompt plan, insert extraction_batches
14	//      and oracle_context_packs rows
15	//   6. Build BatchRequest[] (customId = extraction_batches.id)
16	//   7. Call adapter.submitBatch — submits the JSONL to OpenAI / GCS for Vertex
17	//   8. Insert provider_batch_jobs row with the providerBatchId + metadata
18	//   9. Link all extraction_batches rows to the provider_batch_jobs row
19	//
20	// The drain task (claim-extraction-batch-drain.ts) is what runs validation +
21	// promotion when the batch completes. This task only submits.
22	
23	import { schedules } from '@trigger.dev/sdk/v3';
24	import { and, eq, inArray } from 'drizzle-orm';
25	import { createHash } from 'node:crypto';
26	import { getDirectDb } from '@oracle/db/client';
27	import {
28	  employees,
29	  extractionBatches,
30	  jobRuns,
31	  messages,
32	  oracleContextPacks,
33	  providerBatchJobs,
34	  settings,
35	} from '@oracle/db';
36	import {
37	  buildStandardAdapters,
38	  OracleAIClient,
39	  supportsBatch,
40	  zodToJsonSchema,
41	  makeBlock,
42	  EXTRACTION_SYSTEM_PROMPT,
43	  EXTRACTION_PROMPT_VERSION,
44	  ExtractionOutputSchema,
45	  formatConversationSegment,
46	  loadClaimCorrectionLessonPack,
47	  type BatchRequest,
48	  type FormattedMessage,
49	} from '@oracle/ai';
50	import {
51	  BATCH_SIZE,
52	  buildContextPackInsert,
53	  groupIntoSegments,
54	  resolveExtractionRoute,
55	} from './claim-extraction';
56	
57	export interface BatchSubmitTotals {
58	  ok: boolean;
59	  skipped: boolean;
60	  reason?: string;
61	  segmentsSubmitted: number;
62	  providerBatchId?: string;
63	}
64	
65	export async function runClaimExtractionBatchSubmitOnce(
66	  triggerRunId: string,
67	): Promise<BatchSubmitTotals> {
68	  const db = getDirectDb();
69	  const startedAt = new Date();
70	
71	  const [jobRun] = await db
72	    .insert(jobRuns)
73	    .values({
74	      triggerRunId,
75	      jobType: 'claim-extraction-batch-submit',
76	      status: 'running',
77	      startedAt,
78	      inputJson: { batchSize: BATCH_SIZE },
79	    })
80	    .returning({ id: jobRuns.id });
81	  if (!jobRun) throw new Error('[claim-extraction-batch-submit] failed to insert job_runs row');
82	
83	  const finish = async (output: Record<string, unknown>) => {
84	    await db
85	      .update(jobRuns)
86	      .set({ status: 'complete', finishedAt: new Date(), outputJson: output })
87	      .where(eq(jobRuns.id, jobRun.id));
88	  };
89	
90	  // Hoisted so the catch can roll back the state this run created.
91	  // - claimedMessageIds: messages we flipped 'pending' → 'processing'.
92	  // - stagedBatchIds / stagedContextPackIds: extraction_batches +
93	  //   oracle_context_packs rows we inserted as part of staging segments.
94	  // - providerAccepted: flipped to true the moment adapter.submitBatch returns
95	  //   successfully. If a failure happens after that, the batch is live at the
96	  //   provider and the staging rows are still needed (drain finds them by
97	  //   customId from the batch result, not by provider_batch_job_id), so we
98	  //   leave them in place and log loudly instead of cleaning up.
99	  let claimedMessageIds: string[] = [];
100	  const stagedBatchIds: string[] = [];
101	  const stagedContextPackIds: string[] = [];
102	  let providerAccepted = false;
103	  let providerBatchIdForRecovery: string | null = null;
104	  let providerBatchJobInserted = false;
105	
106	  try {
107	    // 1. Dispatch-mode gate — mirror image of the sync worker.
108	    const dispatchModeRow = await db
109	      .select({ value: settings.value })
110	      .from(settings)
111	      .where(eq(settings.key, 'extraction_dispatch_mode'))
112	      .limit(1);
113	    const dispatchMode = (dispatchModeRow[0]?.value as string | undefined) ?? 'sync';
114	    if (dispatchMode !== 'batch') {
115	      await finish({ skipped: true, reason: `extraction_dispatch_mode=${dispatchMode}` });
116	      return { ok: true, skipped: true, reason: `extraction_dispatch_mode=${dispatchMode}`, segmentsSubmitted: 0 };
117	    }
118	
119	    // 2. Resolve route + check adapter capability.
120	    const route = await resolveExtractionRoute(db);
121	    const correctionLessons = await loadClaimCorrectionLessonPack(db);
122	    const adapters = buildStandardAdapters();
123	    const adapter = adapters[route.provider];
124	    if (!adapter) {
125	      await finish({ skipped: true, reason: `no adapter registered for provider ${route.provider}` });
126	      return { ok: true, skipped: true, reason: `no adapter for ${route.provider}`, segmentsSubmitted: 0 };
127	    }
128	    if (!supportsBatch(adapter)) {
129	      await finish({ skipped: true, reason: `adapter ${route.provider} does not implement Batch API` });
130	      return { ok: true, skipped: true, reason: `adapter ${route.provider} does not support batch`, segmentsSubmitted: 0 };
131	    }
132	
133	    // 3. Pull pending messages.
134	    const pendingMessages = await db
135	      .select({
136	        id: messages.id,
137	        channelId: messages.channelId,
138	        employeeId: messages.employeeId,
139	        role: messages.role,
140	        content: messages.content,
141	        createdAt: messages.createdAt,
142	        authorName: employees.name,
143	      })
144	      .from(messages)
145	      .leftJoin(employees, eq(employees.id, messages.employeeId))
146	      .where(and(eq(messages.extractionStatus, 'pending'), eq(messages.role, 'user')))
147	      .orderBy(messages.createdAt)
148	      .limit(BATCH_SIZE);
149	
150	    if (pendingMessages.length === 0) {
151	      await finish({ segmentsSubmitted: 0, reason: 'no pending messages' });
152	      return { ok: true, skipped: false, segmentsSubmitted: 0 };
153	    }
154	
155	    // 4. Mark as 'processing' for idempotency.
156	    const messageIds = pendingMessages.map((m) => m.id);
157	    claimedMessageIds = messageIds;
158	    await db
159	      .update(messages)
160	      .set({ extractionStatus: 'processing' })
161	      .where(inArray(messages.id, messageIds));
162	
163	    // 5. Group into segments + 6. Build extraction_batches + context_packs + BatchRequest list.
164	    const segments = groupIntoSegments(pendingMessages);
165	    const client = new OracleAIClient({ adapters, fallbackOnError: false });
166	    const requests: BatchRequest[] = [];
167	    const allMessageIdsForFailure: string[] = [];
168	
169	    for (const segment of segments) {
170	      const segmentIds = segment.map((m) => m.id);
171	      allMessageIdsForFailure.push(...segmentIds);
172	      const userMessages = segment.filter((m) => m.role === 'user');
173	      if (userMessages.length === 0) {
174	        // Skip empty segments at submit time — mark messages as 'skipped'.
175	        await db
176	          .update(messages)
177	          .set({ extractionStatus: 'skipped', extractedAt: new Date() })
178	          .where(inArray(messages.id, segmentIds));
179	        continue;
180	      }
181	
182	      const formatted = formatConversationSegment(segment);
183	      const blocks = [
184	        makeBlock({
185	          id: 'extraction-system',
186	          label: 'Extraction system prompt',
187	          kind: 'stable_system',
188	          content: EXTRACTION_SYSTEM_PROMPT,
189	          reasonIncluded: 'extraction prompt v' + EXTRACTION_PROMPT_VERSION,
190	        }),
191	        ...(correctionLessons.promptBlock
192	          ? [
193	              makeBlock({
194	                id: 'reviewer-correction-lessons',
195	                label: 'Approved reviewer correction lessons',
196	                kind: 'semi_stable_domain_context' as const,
197	                content: correctionLessons.promptBlock,
198	                reasonIncluded: 'approved claim revisions teach extraction corrections',
199	              }),
200	            ]
201	          : []),
202	        makeBlock({
203	          id: 'segment',
204	          label: 'Conversation segment to extract from',
205	          kind: 'dynamic_input',
206	          content: formatted,
207	          reasonIncluded: `segment of ${segment.length} message(s) in this batch`,
208	        }),
209	      ];
210	      const plan = client.compile({
211	        taskType: 'message_claim_extraction',
212	        routeId: route.routeId,
213	        promptVersion: EXTRACTION_PROMPT_VERSION,
214	        blocks,
215	        observability: { includedMessageIds: segmentIds },
216	      });
217	      const sourceHash = createHash('sha256').update(formatted, 'utf8').digest('hex');
218	
219	      // Stage extraction_batches row in pending_model status (no model_run_id
220	      // yet — that gets filled in at drain time when results come back).
221	      const [batch] = await db
222	        .insert(extractionBatches)
223	        .values({
224	          jobRunId: jobRun.id,
225	          batchType: 'message_segment',
226	          status: 'pending_model',
227	          sourceMessageIds: segmentIds,
228	          sourceHash,
229	          modelRunIdsAttempted: [],
230	          routeIdsAttempted: [route.routeId],
231	        })
232	        .returning({ id: extractionBatches.id });
233	      if (!batch) throw new Error('[batch-submit] failed to insert extraction_batches row');
234	      // Track for rollback immediately — if the context_pack insert below
235	      // throws, this row is already orphaned and the catch needs to delete it.
236	      stagedBatchIds.push(batch.id);
237	
238	      const [contextPack] = await db
239	        .insert(oracleContextPacks)
240	        .values(buildContextPackInsert(plan))
241	        .returning({ id: oracleContextPacks.id });
242	      if (!contextPack) throw new Error('[batch-submit] failed to insert oracle_context_packs row');
243	      stagedContextPackIds.push(contextPack.id);
244	
245	      await db
246	        .update(extractionBatches)
247	        .set({ contextPackId: contextPack.id })
248	        .where(eq(extractionBatches.id, batch.id));
249	
250	      requests.push({
251	        customId: batch.id, // extraction_batches.id IS the customId so drain can map results
252	        plan,
253	      });
254	    }
255	
256	    if (requests.length === 0) {
257	      await finish({ segmentsSubmitted: 0, reason: 'all segments were user-message-free; no batch submitted' });
258	      return { ok: true, skipped: false, segmentsSubmitted: 0 };
259	    }
260	
261	    // 7. Submit batch via adapter.
262	    const jsonSchema = zodToJsonSchema(ExtractionOutputSchema);
263	    const submitResult = await adapter.submitBatch!({
264	      route,
265	      requests,
266	      jsonSchema,
267	    });
268	    // The provider has accepted the batch — from here on, staging rows MUST
269	    // survive any catch path because the drain task will need them to map
270	    // results back via customId.
271	    providerAccepted = true;
272	    providerBatchIdForRecovery = submitResult.providerBatchId;
273	
274	    // 8. Insert provider_batch_jobs row.
275	    const [batchJob] = await db
276	      .insert(providerBatchJobs)
277	      .values({
278	        provider: route.provider,
279	        providerBatchId: submitResult.providerBatchId,
280	        status: 'submitted',
281	        taskType: 'message_claim_extraction',
282	        routeId: route.routeId,
283	        modelId: route.modelId,
284	        requestCount: requests.length,
285	        providerMetadataJson: submitResult.providerMetadata,
286	      })
287	      .returning({ id: providerBatchJobs.id });
288	    if (!batchJob) throw new Error('[batch-submit] failed to insert provider_batch_jobs row');
289	    providerBatchJobInserted = true;
290	
291	    // 9. Link extraction_batches rows to the batch job.
292	    await db
293	      .update(extractionBatches)
294	      .set({ providerBatchJobId: batchJob.id })
295	      .where(inArray(extractionBatches.id, stagedBatchIds));
296	
297	    await finish({
298	      segmentsSubmitted: requests.length,
299	      providerBatchId: submitResult.providerBatchId,
300	      providerBatchJobId: batchJob.id,
301	    });
302	    return {
303	      ok: true,
304	      skipped: false,
305	      segmentsSubmitted: requests.length,
306	      providerBatchId: submitResult.providerBatchId,
307	    };
308	  } catch (err) {
309	    const errMsg = err instanceof Error ? err.message : String(err);
310	
311	    // Two failure regimes:
312	    //
313	    //  (a) providerAccepted === false: the failure happened before the
314	    //      provider accepted the batch. Nothing is live upstream. Roll back
315	    //      everything this run created — messages back to pending, staged
316	    //      extraction_batches + oracle_context_packs deleted — so the next
317	    //      cron tick gets a clean retry and the admin observability surface
318	    //      isn't littered with stale pending_model rows that will never get
319	    //      drained.
320	    //
321	    //  (b) providerAccepted === true but providerBatchJobInserted === false:
322	    //      the provider has an upstream batch, but Oracle has no durable row
323	    //      for the drain task to poll. That upstream batch is intentionally
324	    //      abandoned; reset local state so the next cron can submit a tracked
325	    //      retry instead of leaving messages stuck as 'processing'.
326	    //
327	    //  (c) providerBatchJobInserted === true: the provider batch is tracked.
328	    //      A failure after that point means messages stay 'processing' and
329	    //      staging rows MUST be kept — drain can recover by polling the job.
330	    if (!providerAccepted || !providerBatchJobInserted) {
331	      if (providerAccepted) {
332	        console.error(
333	          '[claim-extraction-batch-submit] provider accepted a batch but local provider_batch_jobs insert failed; abandoning upstream batch and resetting local state',
334	          { providerBatchId: providerBatchIdForRecovery, error: errMsg },
335	        );
336	      }
337	      if (claimedMessageIds.length > 0) {
338	        try {
339	          await db
340	            .update(messages)
341	            .set({ extractionStatus: 'pending' })
342	            .where(
343	              and(
344	                inArray(messages.id, claimedMessageIds),
345	                eq(messages.extractionStatus, 'processing'),
346	              ),
347	            );
348	        } catch (revertErr) {
349	          console.error(
350	            '[claim-extraction-batch-submit] failed to revert messages to pending',
351	            revertErr,
352	          );
353	        }
354	      }
355	      // Delete the FK child first (oracle_context_packs is referenced from
356	      // extraction_batches.context_pack_id), then the parent staging rows.
357	      // Both deletes are scoped to ids this run created, so they cannot
358	      // touch any other batch's state.
359	      if (stagedBatchIds.length > 0) {
360	        try {
361	          await db
362	            .delete(extractionBatches)
363	            .where(inArray(extractionBatches.id, stagedBatchIds));
364	        } catch (cleanupErr) {
365	          console.error(
366	            '[claim-extraction-batch-submit] failed to delete staged extraction_batches rows',
367	            cleanupErr,
368	          );
369	        }
370	      }
371	      if (stagedContextPackIds.length > 0) {
372	        try {
373	          await db
374	            .delete(oracleContextPacks)
375	            .where(inArray(oracleContextPacks.id, stagedContextPackIds));
376	        } catch (cleanupErr) {
377	          console.error(
378	            '[claim-extraction-batch-submit] failed to delete staged oracle_context_packs rows',
379	            cleanupErr,
380	          );
381	        }
382	      }
383	    } else {
384	      console.error(
385	        '[claim-extraction-batch-submit] failure after tracked provider batch creation — staging rows + messages left as-is for drain or manual recovery',
386	        {
387	          providerBatchId: providerBatchIdForRecovery,
388	          stagedBatchIds,
389	          stagedContextPackIds,
390	          claimedMessageCount: claimedMessageIds.length,
391	          error: errMsg,
392	        },
393	      );
394	    }
395	
396	    await db
397	      .update(jobRuns)
398	      .set({ status: 'failed', finishedAt: new Date(), error: errMsg })
399	      .where(eq(jobRuns.id, jobRun.id));
400	    throw err;
401	  }
402	}
403	
404	export const claimExtractionBatchSubmitTask = schedules.task({
405	  id: 'claim-extraction-batch-submit',
406	  cron: '0 */4 * * *',
407	  maxDuration: 60 * 5,
408	  run: async (_payload, { ctx }) => {
409	    return runClaimExtractionBatchSubmitOnce(ctx.run.id);
410	  },
411	});
412	
413	// Suppress the unused-warning for FormattedMessage which is imported solely
414	// to satisfy the implicit-any check on groupIntoSegments callers in some
415	// downstream callers. Keep the import — re-importing it elsewhere is noisier.
416	export type { FormattedMessage };
