1	// D14 — Claim extraction drain task (Batch API path)
2	//
3	// Cron: every 10 minutes. Polls in-flight provider_batch_jobs rows for the
4	// claim_extraction task type. When a batch reaches 'completed' status, walks
5	// each per-request result and runs the existing R5/R5.5 validation +
6	// promotion pipeline (processSegmentOutput from claim-extraction.ts) so
7	// batch-mode candidates land in the DB through the SAME code path as sync.
8	//
9	// Cost dashboards: every model_runs row inserted by this task has
10	// dispatch_mode='batch' so admin /admin/ai pages can distinguish batch from
11	// sync once the model_runs_with_usage view is updated to expose the column
12	// (HANDOFF.md Step 0 note).
13	//
14	// Per-result error handling:
15	//   - item.success === false  → extraction_batches.status='failed', messages
16	//     marked 'failed' with the provider error message
17	//   - schema parse fails       → same
18	//   - happy path               → model_runs + model_run_usage_details + batch
19	//     marked 'model_complete', then processSegmentOutput runs the validators
20	
21	import { schedules } from '@trigger.dev/sdk/v3';
22	import { eq, inArray, sql } from 'drizzle-orm';
23	import { getDirectDb } from '@oracle/db/client';
24	import {
25	  employees,
26	  extractionBatches,
27	  jobRuns,
28	  messages,
29	  modelRunUsageDetails,
30	  modelRuns,
31	  providerBatchJobs,
32	  settings,
33	  type OracleDb,
34	  type ProviderBatchJob,
35	} from '@oracle/db';
36	import {
37	  buildStandardAdapters,
38	  ExtractionOutputSchema,
39	  getOracleRoute,
40	  supportsBatch,
41	  type BatchResultItem,
42	  type BatchStatus,
43	  type ExtractionOutput,
44	  type FormattedMessage,
45	  type OracleModelRoute,
46	} from '@oracle/ai';
47	import {
48	  buildOracleClient,
49	  loadActiveTopDomainIds,
50	  loadEntityRegistry,
51	  processSegmentOutput,
52	} from './claim-extraction';
53	
54	export interface BatchDrainTotals {
55	  ok: boolean;
56	  batchesPolled: number;
57	  batchesCompleted: number;
58	  segmentsProcessed: number;
59	  claimsPromoted: number;
60	  duplicatesAppended: number;
61	  rejections: number;
62	  errors: number;
63	}
64	
65	export async function runClaimExtractionBatchDrainOnce(
66	  triggerRunId: string,
67	): Promise<BatchDrainTotals> {
68	  const db = getDirectDb();
69	  const startedAt = new Date();
70	  const totals: Omit<BatchDrainTotals, 'ok'> = {
71	    batchesPolled: 0,
72	    batchesCompleted: 0,
73	    segmentsProcessed: 0,
74	    claimsPromoted: 0,
75	    duplicatesAppended: 0,
76	    rejections: 0,
77	    errors: 0,
78	  };
79	
80	  const [jobRun] = await db
81	    .insert(jobRuns)
82	    .values({
83	      triggerRunId,
84	      jobType: 'claim-extraction-batch-drain',
85	      status: 'running',
86	      startedAt,
87	    })
88	    .returning({ id: jobRuns.id });
89	  if (!jobRun) throw new Error('[claim-extraction-batch-drain] failed to insert job_runs row');
90	
91	  try {
92	    const pendingBatches = await db
93	      .select()
94	      .from(providerBatchJobs)
95	      .where(
96	        sql`${providerBatchJobs.status} IN ('submitted','in_progress') AND ${providerBatchJobs.taskType} = 'message_claim_extraction'`,
97	      );
98	
99	    if (pendingBatches.length === 0) {
100	      await db
101	        .update(jobRuns)
102	        .set({ status: 'complete', finishedAt: new Date(), outputJson: { ...totals, reason: 'no pending batches' } })
103	        .where(eq(jobRuns.id, jobRun.id));
104	      return { ok: true, ...totals };
105	    }
106	
107	    const adapters = buildStandardAdapters();
108	    const activeTopDomainIds = await loadActiveTopDomainIds(db);
109	    const entityRegistry = await loadEntityRegistry(db);
110	    // The OracleAIClient is unused by processSegmentOutput (no model calls are
111	    // made during drain — the model output was produced by the batch already),
112	    // but we instantiate it so the standard adapter map is initialized once.
113	    void buildOracleClient();
114	
115	    for (const batchJob of pendingBatches) {
116	      totals.batchesPolled += 1;
117	      try {
118	        const finalStatus = await drainOneBatch(db, batchJob, adapters, activeTopDomainIds, entityRegistry, totals);
119	        if (finalStatus === 'completed') totals.batchesCompleted += 1;
120	      } catch (err) {
121	        totals.errors += 1;
122	        console.error('[claim-extraction-batch-drain] batch drain failed', batchJob.id, err);
123	        // Don't mark the batch as failed on a transient retrieval error —
124	        // leave it as-is so the next cron tick retries.
125	        await db
126	          .update(providerBatchJobs)
127	          .set({
128	            pollLastAt: new Date(),
129	            errorJson: { message: err instanceof Error ? err.message : String(err), transient: true },
130	          })
131	          .where(eq(providerBatchJobs.id, batchJob.id));
132	      }
133	    }
134	
135	    await db
136	      .update(jobRuns)
137	      .set({ status: 'complete', finishedAt: new Date(), outputJson: totals })
138	      .where(eq(jobRuns.id, jobRun.id));
139	    return { ok: true, ...totals };
140	  } catch (fatalErr) {
141	    await db
142	      .update(jobRuns)
143	      .set({
144	        status: 'failed',
145	        finishedAt: new Date(),
146	        error: fatalErr instanceof Error ? fatalErr.message : String(fatalErr),
147	      })
148	      .where(eq(jobRuns.id, jobRun.id));
149	    throw fatalErr;
150	  }
151	}
152	
153	async function drainOneBatch(
154	  db: OracleDb,
155	  batchJob: ProviderBatchJob,
156	  adapters: ReturnType<typeof buildStandardAdapters>,
157	  activeTopDomainIds: string[],
158	  entityRegistry: Awaited<ReturnType<typeof loadEntityRegistry>>,
159	  totals: Omit<BatchDrainTotals, 'ok'>,
160	): Promise<BatchStatus> {
161	  const adapter = adapters[batchJob.provider as keyof typeof adapters];
162	  if (!adapter || !supportsBatch(adapter)) {
163	    // Provider unsupported — mark the batch failed so it stops being polled.
164	    await db
165	      .update(providerBatchJobs)
166	      .set({
167	        status: 'failed',
168	        completedAt: new Date(),
169	        pollLastAt: new Date(),
170	        errorJson: { message: `no batch-capable adapter for provider ${batchJob.provider}` },
171	      })
172	      .where(eq(providerBatchJobs.id, batchJob.id));
173	    return 'failed';
174	  }
175	
176	  const route = getOracleRoute(batchJob.routeId);
177	  if (!route) {
178	    await db
179	      .update(providerBatchJobs)
180	      .set({
181	        status: 'failed',
182	        completedAt: new Date(),
183	        pollLastAt: new Date(),
184	        errorJson: { message: `route ${batchJob.routeId} no longer in catalog` },
185	      })
186	      .where(eq(providerBatchJobs.id, batchJob.id));
187	    return 'failed';
188	  }
189	
190	  const result = await adapter.retrieveBatch!({
191	    providerBatchId: batchJob.providerBatchId,
192	    providerMetadata: (batchJob.providerMetadataJson as Record<string, unknown> | null) ?? {},
193	    route,
194	  });
195	
196	  // Always update poll_last_at + status + counts.
197	  await db
198	    .update(providerBatchJobs)
199	    .set({
200	      status: result.status,
201	      pollLastAt: new Date(),
202	      completedCount: result.completedCount ?? batchJob.completedCount,
203	      failedCount: result.failedCount ?? batchJob.failedCount,
204	      completedAt: result.status === 'completed' || result.status === 'failed' || result.status === 'expired' || result.status === 'canceled'
205	        ? new Date()
206	        : null,
207	      errorJson: result.error ? { message: result.error } : null,
208	    })
209	    .where(eq(providerBatchJobs.id, batchJob.id));
210	
211	  if (result.status !== 'completed' || !result.results) {
212	    return result.status;
213	  }
214	
215	  // Process each result. customId === extraction_batches.id by submit-task convention.
216	  for (const item of result.results) {
217	    await processBatchResultItem(db, batchJob, route, item, activeTopDomainIds, entityRegistry, totals);
218	  }
219	
220	  await db
221	    .update(providerBatchJobs)
222	    .set({ resultsRetrievedAt: new Date() })
223	    .where(eq(providerBatchJobs.id, batchJob.id));
224	
225	  return 'completed';
226	}
227	
228	async function processBatchResultItem(
229	  db: OracleDb,
230	  batchJob: ProviderBatchJob,
231	  route: OracleModelRoute,
232	  item: BatchResultItem,
233	  activeTopDomainIds: string[],
234	  entityRegistry: Awaited<ReturnType<typeof loadEntityRegistry>>,
235	  totals: Omit<BatchDrainTotals, 'ok'>,
236	): Promise<void> {
237	  const extractionBatchId = item.customId;
238	
239	  // Load the extraction_batches row + its segment messages.
240	  const [batchRow] = await db
241	    .select()
242	    .from(extractionBatches)
243	    .where(eq(extractionBatches.id, extractionBatchId))
244	    .limit(1);
245	  if (!batchRow) {
246	    console.warn('[claim-extraction-batch-drain] no extraction_batches row for customId', extractionBatchId);
247	    totals.errors += 1;
248	    return;
249	  }
250	
251	  const segmentMessageIds = (batchRow.sourceMessageIds as string[] | null) ?? [];
252	  if (segmentMessageIds.length === 0) {
253	    totals.errors += 1;
254	    return;
255	  }
256	
257	  // Load FormattedMessage[] for the segment. The shape mirrors the sync
258	  // worker's pending-messages SELECT.
259	  const segmentRows = await db
260	    .select({
261	      id: messages.id,
262	      channelId: messages.channelId,
263	      employeeId: messages.employeeId,
264	      role: messages.role,
265	      content: messages.content,
266	      createdAt: messages.createdAt,
267	      authorName: employees.name,
268	    })
269	    .from(messages)
270	    .leftJoin(employees, eq(employees.id, messages.employeeId))
271	    .where(inArray(messages.id, segmentMessageIds))
272	    .orderBy(messages.createdAt);
273	  const segment = segmentRows as unknown as FormattedMessage[];
274	
275	  // Per-request failure path (provider returned non-success for this customId).
276	  if (!item.success) {
277	    await markBatchFailed(db, extractionBatchId, segmentMessageIds, item.error ?? 'batch result error');
278	    totals.errors += 1;
279	    return;
280	  }
281	
282	  // Parse / validate the output against the extraction schema.
283	  let modelOutput: ExtractionOutput;
284	  try {
285	    modelOutput = ExtractionOutputSchema.parse(item.output);
286	  } catch (parseErr) {
287	    await markBatchFailed(
288	      db,
289	      extractionBatchId,
290	      segmentMessageIds,
291	      `output failed schema validation: ${parseErr instanceof Error ? parseErr.message : String(parseErr)}`,
292	    );
293	    totals.errors += 1;
294	    return;
295	  }
296	
297	  // Insert model_runs row (the batch path lacks a per-request latency, so
298	  // dispatch_mode + provider_request_id are the main signals).
299	  const [modelRun] = await db
300	    .insert(modelRuns)
301	    .values({
302	      taskType: 'claim-extraction',
303	      model: route.modelId,
304	      provider: route.provider,
305	      promptVersion: undefined,
306	      inputTokens: item.usage?.inputTokens ?? null,
307	      outputTokens: item.usage?.outputTokens ?? null,
308	      latencyMs: null,
309	      success: true,
310	      dispatchMode: 'batch',
311	    })
312	    .returning({ id: modelRuns.id });
313	  if (!modelRun) throw new Error('[batch-drain] failed to insert model_runs row');
314	
315	  await db.insert(modelRunUsageDetails).values({
316	    modelRunId: modelRun.id,
317	    contextPackId: batchRow.contextPackId,
318	    routeId: route.routeId,
319	    inputTokens: item.usage?.inputTokens ?? null,
320	    cachedInputTokens: item.usage?.cachedInputTokens ?? null,
321	    cacheWriteTokens: item.usage?.cacheWriteTokens ?? null,
322	    outputTokens: item.usage?.outputTokens ?? null,
323	    reasoningTokens: item.usage?.reasoningTokens ?? null,
324	    providerRequestId: item.usage?.providerRequestId ?? null,
325	    rawUsageJson: (item.usage?.rawUsageJson as Record<string, unknown> | undefined) ?? null,
326	  });
327	
328	  await db
329	    .update(extractionBatches)
330	    .set({
331	      modelRunId: modelRun.id,
332	      modelRunIdsAttempted: [modelRun.id],
333	      rawModelOutput: modelOutput as unknown as Record<string, unknown>,
334	      status: 'model_complete',
335	    })
336	    .where(eq(extractionBatches.id, extractionBatchId));
337	
338	  // Hand off to the shared per-segment processor.
339	  const outcome = await processSegmentOutput({
340	    db,
341	    route,
342	    activeTopDomainIds,
343	    entityRegistry,
344	    segment,
345	    extractionBatchId,
346	    modelRunId: modelRun.id,
347	    sourceHash: batchRow.sourceHash,
348	    modelOutput,
349	  });
350	
351	  totals.segmentsProcessed += 1;
352	  totals.claimsPromoted += outcome.claimsPromoted;
353	  totals.duplicatesAppended += outcome.duplicatesAppended;
354	  totals.rejections += outcome.rejections;
355	}
