357	async function markBatchFailed(
358	  db: OracleDb,
359	  extractionBatchId: string,
360	  segmentMessageIds: string[],
361	  errorMsg: string,
362	): Promise<void> {
363	  await db
364	    .update(extractionBatches)
365	    .set({ status: 'failed', error: errorMsg, finishedAt: new Date() })
366	    .where(eq(extractionBatches.id, extractionBatchId));
367	  if (segmentMessageIds.length > 0) {
368	    await db
369	      .update(messages)
370	      .set({ extractionStatus: 'failed', extractionError: errorMsg })
371	      .where(inArray(messages.id, segmentMessageIds));
372	  }
373	}
