92	// ─────────────────────────────────────────────────────────────────────────
93	// Top-level Trigger.dev task
94	// ─────────────────────────────────────────────────────────────────────────
95	
96	export interface ClaimExtractionRunTotals {
97	  ok: boolean;
98	  batchesProcessed: number;
99	  candidatesStaged: number;
100	  claimsPromoted: number;
101	  duplicatesAppended: number;
102	  rejections: number;
103	  circuitBreakerTrips: number;
104	  messagesProcessed: number;
105	  errors: number;
106	}
107	
108	// Core run body extracted so wet-test runners and future integration tests
109	// can invoke a single pass without going through the Trigger.dev runtime.
110	// `triggerRunId` accepts a real `ctx.run.id` from Trigger.dev OR any unique
111	// string for local invocation (the value is stored on the `job_runs` row).
112	export async function runClaimExtractionOnce(
113	  triggerRunId: string,
114	): Promise<ClaimExtractionRunTotals> {
115	    const db = getDirectDb();
116	    const client = buildOracleClient();
117	    const startedAt = new Date();
118	
119	    const [jobRun] = await db
120	      .insert(jobRuns)
121	      .values({
122	        triggerRunId,
123	        jobType: 'claim-extraction',
124	        status: 'running',
125	        startedAt,
126	        inputJson: { batchSize: BATCH_SIZE },
127	      })
128	      .returning({ id: jobRuns.id });
129	    if (!jobRun) throw new Error('[claim-extraction] failed to insert job_runs row');
130	
131	    const totals = {
132	      batchesProcessed: 0,
133	      candidatesStaged: 0,
134	      claimsPromoted: 0,
135	      duplicatesAppended: 0,
136	      rejections: 0,
137	      circuitBreakerTrips: 0,
138	      messagesProcessed: 0,
139	      errors: 0,
140	    };
141	
142	    try {
143	      // 0. Dispatch-mode gate. If settings.extraction_dispatch_mode === 'batch'
144	      //    the batch-submit worker owns extraction; the sync path bails. The
145	      //    flag is read every run so admins can flip back to sync without
146	      //    redeploying. See DECISIONS.md D14.
147	      const dispatchModeRow = await db
148	        .select({ value: settings.value })
149	        .from(settings)
150	        .where(eq(settings.key, 'extraction_dispatch_mode'))
151	        .limit(1);
152	      const dispatchMode = (dispatchModeRow[0]?.value as string | undefined) ?? 'sync';
153	      if (dispatchMode === 'batch') {
154	        await db
155	          .update(jobRuns)
156	          .set({
157	            status: 'complete',
158	            finishedAt: new Date(),
159	            outputJson: { ...totals, skipped: true, reason: 'extraction_dispatch_mode=batch — handled by claim-extraction-batch-submit' },
160	          })
161	          .where(eq(jobRuns.id, jobRun.id));
162	        return { ok: true, ...totals };
163	      }
164	
165	      // 0.5. Reaper — reset messages stuck in 'processing'. A worker crash
166	      //      between the 'processing' flip (step 3) and the terminal status
167	      //      update leaves messages stranded: only 'pending' is ever
168	      //      re-selected, so a stuck 'processing' row would never be retried.
169	      //      Reset any 'processing' row older than 2 hours back to 'pending'
170	      //      so the next pass picks it up. Idempotent (no-op when nothing is
171	      //      stuck) and uses created_at since 'processing' has no own timestamp.
172	      const reaped = await db
173	        .update(messages)
174	        .set({ extractionStatus: 'pending' })
175	        .where(
176	          and(
177	            eq(messages.extractionStatus, 'processing'),
178	            sql`${messages.createdAt} < now() - interval '2 hours'`,
179	          ),
180	        )
181	        .returning({ id: messages.id });
182	      if (reaped.length > 0) {
183	        console.warn(
184	          `[claim-extraction] reaper reset ${reaped.length} message(s) stuck in 'processing' (>2h) back to 'pending'.`,
185	        );
186	      }
187	
188	      // 1. Resolve the curated extraction route.
189	      const route = await resolveExtractionRoute(db);
190	      const activeTopDomainIds = await loadActiveTopDomainIds(db);
191	      const entityRegistry = await loadEntityRegistry(db);
192	      const correctionLessons = await loadClaimCorrectionLessonPack(db);
193	
194	      // 2. Pull pending user messages.
195	      const pendingMessages = await db
196	        .select({
197	          id: messages.id,
198	          channelId: messages.channelId,
199	          employeeId: messages.employeeId,
200	          role: messages.role,
201	          content: messages.content,
202	          createdAt: messages.createdAt,
203	          authorName: employees.name,
204	        })
205	        .from(messages)
206	        .leftJoin(employees, eq(employees.id, messages.employeeId))
207	        .where(and(eq(messages.extractionStatus, 'pending'), eq(messages.role, 'user')))
208	        .orderBy(messages.createdAt)
209	        .limit(BATCH_SIZE);
210	
211	      if (pendingMessages.length === 0) {
212	        await db
213	          .update(jobRuns)
214	          .set({ status: 'complete', finishedAt: new Date(), outputJson: totals })
215	          .where(eq(jobRuns.id, jobRun.id));
216	        return { ok: true, ...totals };
217	      }
218	
219	      // 3. Mark all fetched messages as 'processing' (idempotency guard).
220	      const messageIds = pendingMessages.map((m) => m.id);
221	      await db
222	        .update(messages)
223	        .set({ extractionStatus: 'processing' })
224	        .where(inArray(messages.id, messageIds));
225	
226	      // 4. Group by channel → 60-min conversation segments.
227	      const segments = groupIntoSegments(pendingMessages);
228	
229	      // 5. Process each segment as an extraction_batches row.
230	      for (const segment of segments) {
231	        try {
232	          const outcome = await processSegment({
233	            db,
234	            client,
235	            route,
236	            activeTopDomainIds,
237	            entityRegistry,
238	            correctionLessonsPromptBlock: correctionLessons.promptBlock,
239	            jobRunId: jobRun.id,
240	            segment,
241	          });
242	          totals.batchesProcessed += 1;
243	          totals.candidatesStaged += outcome.candidatesStaged;
244	          totals.claimsPromoted += outcome.claimsPromoted;
245	          totals.duplicatesAppended += outcome.duplicatesAppended;
246	          totals.rejections += outcome.rejections;
247	          totals.circuitBreakerTrips += outcome.circuitBreakerTripped ? 1 : 0;
248	          totals.messagesProcessed += outcome.messagesProcessed;
249	        } catch (segErr) {
250	          totals.errors += 1;
251	          console.error('[claim-extraction] segment processing failed', segErr);
252	          // The segment-level error path already updates the batch + messages
253	          // to 'failed'; nothing more to do here.
254	        }
255	      }
256	
257	      await db
258	        .update(jobRuns)
259	        .set({ status: 'complete', finishedAt: new Date(), outputJson: totals })
260	        .where(eq(jobRuns.id, jobRun.id));
261	
262	      return { ok: true, ...totals };
263	    } catch (fatalErr) {
264	      await db
265	        .update(jobRuns)
266	        .set({
267	          status: 'failed',
268	          finishedAt: new Date(),
269	          error: fatalErr instanceof Error ? fatalErr.message : String(fatalErr),
270	        })
271	        .where(eq(jobRuns.id, jobRun.id));
272	      throw fatalErr;
273	    }
274	}
