288	// ─────────────────────────────────────────────────────────────────────────
289	// Per-segment processing
290	// ─────────────────────────────────────────────────────────────────────────
291	
292	interface SegmentOutcome {
293	  candidatesStaged: number;
294	  claimsPromoted: number;
295	  duplicatesAppended: number;
296	  rejections: number;
297	  circuitBreakerTripped: boolean;
298	  messagesProcessed: number;
299	}
300	
301	interface ProcessSegmentArgs {
302	  db: OracleDb;
303	  client: OracleAIClient;
304	  route: OracleModelRoute;
305	  activeTopDomainIds: string[];
306	  entityRegistry: RegistryEntity[];
307	  correctionLessonsPromptBlock: string;
308	  jobRunId: string;
309	  segment: FormattedMessage[];
310	}
311	
312	async function processSegment(args: ProcessSegmentArgs): Promise<SegmentOutcome> {
313	  const {
314	    db,
315	    client,
316	    route,
317	    activeTopDomainIds,
318	    entityRegistry,
319	    correctionLessonsPromptBlock,
320	    jobRunId,
321	    segment,
322	  } = args;
323	  const segmentIds = segment.map((m) => m.id);
324	  const userMessages = segment.filter((m) => m.role === 'user');
325	
326	  const outcome: SegmentOutcome = {
327	    candidatesStaged: 0,
328	    claimsPromoted: 0,
329	    duplicatesAppended: 0,
330	    rejections: 0,
331	    circuitBreakerTripped: false,
332	    messagesProcessed: 0,
333	  };
334	
335	  if (userMessages.length === 0) {
336	    await db
337	      .update(messages)
338	      .set({ extractionStatus: 'skipped', extractedAt: new Date() })
339	      .where(inArray(messages.id, segmentIds));
340	    outcome.messagesProcessed = segmentIds.length;
341	    return outcome;
342	  }
343	
344	  // Compile the prompt plan.
345	  const formatted = formatConversationSegment(segment);
346	  const blocks = [
347	    makeBlock({
348	      id: 'extraction-system',
349	      label: 'Extraction system prompt',
350	      kind: 'stable_system',
351	      content: EXTRACTION_SYSTEM_PROMPT,
352	      reasonIncluded: 'extraction prompt v' + EXTRACTION_PROMPT_VERSION,
353	    }),
354	    ...(correctionLessonsPromptBlock
355	      ? [
356	          makeBlock({
357	            id: 'reviewer-correction-lessons',
358	            label: 'Approved reviewer correction lessons',
359	            kind: 'semi_stable_domain_context' as const,
360	            content: correctionLessonsPromptBlock,
361	            reasonIncluded: 'approved claim revisions teach extraction corrections',
362	          }),
363	        ]
364	      : []),
365	    makeBlock({
366	      id: 'segment',
367	      label: 'Conversation segment to extract from',
368	      kind: 'dynamic_input',
369	      content: formatted,
370	      reasonIncluded: `segment of ${segment.length} message(s) in this batch`,
371	    }),
372	  ];
373	  const plan = client.compile({
374	    taskType: 'message_claim_extraction',
375	    routeId: route.routeId,
376	    promptVersion: EXTRACTION_PROMPT_VERSION,
377	    blocks,
378	    observability: { includedMessageIds: segmentIds },
379	  });
380	  const sourceHash = createHash('sha256').update(formatted, 'utf8').digest('hex');
381	
382	  // 1. Stage an extraction_batches row.
383	  const [batch] = await db
384	    .insert(extractionBatches)
385	    .values({
386	      jobRunId,
387	      batchType: 'message_segment',
388	      status: 'pending_model',
389	      sourceMessageIds: segmentIds,
390	      sourceHash,
391	      modelRunIdsAttempted: [],
392	      routeIdsAttempted: [route.routeId],
393	    })
394	    .returning({ id: extractionBatches.id });
395	  if (!batch) throw new Error('[claim-extraction] failed to insert extraction_batches row');
396	
397	  // 2. Stage the context pack BEFORE the model call so its ID can thread
398	  //    through. model_run_id stays null until the model_run is logged.
399	  const [contextPack] = await db
400	    .insert(oracleContextPacks)
401	    .values(buildContextPackInsert(plan))
402	    .returning({ id: oracleContextPacks.id });
403	  if (!contextPack) throw new Error('[claim-extraction] failed to insert oracle_context_packs row');
404	
405	  await db
406	    .update(extractionBatches)
407	    .set({ contextPackId: contextPack.id })
408	    .where(eq(extractionBatches.id, batch.id));
409	
410	  // 3. Call the model.
411	  const callStartedAt = Date.now();
412	  let modelOutput: ExtractionOutput | null = null;
413	  let modelRunId: string | null = null;
414	  let modelError: unknown = null;
415	
416	  try {
417	    const result = await client.runObject<ExtractionOutput>({
418	      taskType: 'message_claim_extraction',
419	      routeId: route.routeId,
420	      promptVersion: EXTRACTION_PROMPT_VERSION,
421	      blocks,
422	      schema: ExtractionOutputSchema,
423	      observability: { includedMessageIds: segmentIds },
424	      providerOptions: {
425	        cache: {
426	          preferExplicitCache: route.provider === 'vertex',
427	          cacheTtlSeconds: 15 * 60,
428	          expectedReuseCount: 2,
429	          persistProviderCacheRecord: route.provider === 'vertex',
430	          sourceDescription: `message segment ${segmentIds[0]}..${segmentIds[segmentIds.length - 1]}`,
431	          cleanupOwner: 'claim-extraction-worker',
432	          createdByJobRunId: jobRunId,
433	          latestPlannedReuseStep: 'message_claim_extraction',
434	        },
435	      },
436	    });
437	    const latencyMs = Date.now() - callStartedAt;
438	    const actualRouteId = result.routeId ?? route.routeId;
439	    const actualProvider = result.provider ?? route.provider;
440	    const actualModelId = result.modelId ?? route.modelId;
441	
442	    // Log model_runs row.
443	    const [modelRun] = await db
444	      .insert(modelRuns)
445	      .values({
446	        taskType: 'claim-extraction',
447	        model: actualModelId,
448	        provider: actualProvider,
449	        promptVersion: EXTRACTION_PROMPT_VERSION,
450	        inputHash: plan.metadata.stablePrefixHash,
451	        inputTokens: result.usage.inputTokens ?? null,
452	        outputTokens: result.usage.outputTokens ?? null,
453	        latencyMs,
454	        success: result.validation.ok,
455	      })
456	      .returning({ id: modelRuns.id });
457	    if (!modelRun) throw new Error('[claim-extraction] failed to insert model_runs row');
458	    modelRunId = modelRun.id;
459	
460	    // Log model_run_usage_details + back-link context pack.
461	    await db.insert(modelRunUsageDetails).values({
462	      modelRunId: modelRun.id,
463	      contextPackId: contextPack.id,
464	      routeId: actualRouteId,
465	      inputTokens: result.usage.inputTokens ?? null,
466	      cachedInputTokens: result.usage.cachedInputTokens ?? null,
467	      cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
468	      outputTokens: result.usage.outputTokens ?? null,
469	      reasoningTokens: result.usage.reasoningTokens ?? null,
470	      providerRequestId: result.usage.providerRequestId ?? null,
471	      rawUsageJson: result.usage.rawUsageJson ?? null,
472	      fellBackFromRouteId: result.fellBackFromRouteId ?? null,
473	      fallbackReason: result.fallbackReason ?? null,
474	    });
475	    await db
476	      .update(oracleContextPacks)
477	      .set({ modelRunId: modelRun.id })
478	      .where(eq(oracleContextPacks.id, contextPack.id));
479	    await db
480	      .update(extractionBatches)
481	      .set({
482	        modelRunId: modelRun.id,
483	        modelRunIdsAttempted: [modelRun.id],
484	        rawModelOutput: result.object as unknown as Record<string, unknown>,
485	        status: result.validation.ok ? 'model_complete' : 'failed',
486	      })
487	      .where(eq(extractionBatches.id, batch.id));
488	
489	    if (!result.validation.ok) {
490	      throw new Error(
491	        '[claim-extraction] model output failed Zod schema validation: ' +
492	          result.validation.error.message,
493	      );
494	    }
495	    modelOutput = result.object;
496	  } catch (err) {
497	    modelError = err;
498	    if (!modelRunId) {
499	      // The model_runs row was never inserted. Insert a failed one now so
500	      // the batch has provenance.
501	      await db.insert(modelRuns).values({
502	        taskType: 'claim-extraction',
503	        model: route.modelId,
504	        provider: route.provider,
505	        promptVersion: EXTRACTION_PROMPT_VERSION,
506	        latencyMs: Date.now() - callStartedAt,
507	        success: false,
508	        error: err instanceof Error ? err.message : String(err),
509	      });
510	    }
511	    await db
512	      .update(extractionBatches)
513	      .set({
514	        status: 'failed',
515	        error: err instanceof Error ? err.message : String(err),
516	        finishedAt: new Date(),
517	      })
518	      .where(eq(extractionBatches.id, batch.id));
519	    await db
520	      .update(messages)
521	      .set({
522	        extractionStatus: 'failed',
523	        extractionError: err instanceof Error ? err.message : String(err),
524	      })
525	      .where(inArray(messages.id, segmentIds));
526	    outcome.messagesProcessed = segmentIds.length;
527	    return outcome;
528	  }
529	
530	  if (!modelOutput) return outcome;
531	
532	  // 4. Delegate per-candidate validation + promotion + final batch/message
533	  //    status updates to the shared processSegmentOutput function so the
534	  //    batch-drain worker can run identical logic on retrieved Batch API
535	  //    results without duplicating any of it.
536	  return processSegmentOutput({
537	    db,
538	    route,
539	    activeTopDomainIds,
540	    entityRegistry,
541	    segment,
542	    extractionBatchId: batch.id,
543	    modelRunId: modelRunId!,
544	    sourceHash,
545	    modelOutput,
546	    initialOutcome: outcome,
547	  });
548	}
549	
550	// ─────────────────────────────────────────────────────────────────────────
551	// processSegmentOutput — shared per-segment post-model-call processing
552	//
553	// Runs the candidate-before-claim pipeline (R5 quote validation, R5.5
554	// taxonomy validation, sensitivity gate, executePromotion) against an
555	// already-produced ExtractionOutput. Called by BOTH the sync path
556	// (claim-extraction.ts processSegment, immediately after the model call)
557	// AND the batch-drain path (claim-extraction-batch-drain.ts, after pulling
558	// results from the provider Batch API).
559	//
560	// Preconditions the caller must satisfy:
561	//   - extraction_batches row exists (extractionBatchId), in pending_model
562	//     or model_complete status
563	//   - model_runs row exists (modelRunId), with success=true
564	//   - modelOutput parses as ExtractionOutputSchema
565	//
566	// Postconditions:
567	//   - For each claim in modelOutput: extraction_candidates + evidence rows
568	//     inserted, validators run, executePromotion attempted
569	//   - extraction_batches.status updated to 'validation_complete' (or
570	//     'failed_validation_loop' if the circuit breaker tripped)
571	//   - All segment messages marked extraction_status='complete'
572	// ─────────────────────────────────────────────────────────────────────────
573	
574	export interface ProcessSegmentOutputArgs {
575	  db: OracleDb;
576	  route: OracleModelRoute;
577	  activeTopDomainIds: string[];
578	  entityRegistry: RegistryEntity[];
579	  segment: FormattedMessage[];
580	  extractionBatchId: string;
581	  modelRunId: string;
582	  sourceHash: string;
583	  modelOutput: ExtractionOutput;
584	  /** Sync caller passes its accumulator so candidatesStaged etc. roll up. */
585	  initialOutcome?: SegmentOutcome;
586	}
587	
588	export async function processSegmentOutput(
589	  args: ProcessSegmentOutputArgs,
590	): Promise<SegmentOutcome> {
591	  const {
592	    db, route, activeTopDomainIds, entityRegistry, segment,
593	    extractionBatchId, modelRunId, sourceHash, modelOutput,
594	  } = args;
595	  const segmentIds = segment.map((m) => m.id);
596	  const batch = { id: extractionBatchId };
597	  const outcome: SegmentOutcome = args.initialOutcome ?? {
598	    candidatesStaged: 0,
599	    claimsPromoted: 0,
600	    duplicatesAppended: 0,
601	    rejections: 0,
602	    circuitBreakerTripped: false,
603	    messagesProcessed: 0,
604	  };
605	
606	  // Stage candidates + evidence, run R5/R5.5 validators, run promotion.
607	  let consecutiveQuoteFailureCount = 0;
608	  let validationAttemptCount = 0;
609	
610	  for (const extracted of modelOutput.claims) {
611	    validationAttemptCount += 1;
612	
613	    // Insert the candidate row.
614	    const proposedTopDomainIds = mapLegacyDomainsToTopDomains(
615	      extracted.domains as KnowledgeDomain[],
616	    );
617	    const [candidate] = await db
618	      .insert(extractionCandidates)
619	      .values({
620	        extractionBatchId: batch.id,
621	        status: 'pending_validation',
622	        claimType: extracted.claimType,
623	        summary: extracted.summary,
624	        impactScore: extracted.impactScore,
625	        confidenceScore: extracted.confidenceScore,
626	        domains: proposedTopDomainIds satisfies TopLevelDomainId[],
627	        // P2 #1 — proposedEntities now sourced from the model (was hardcoded
628	        // empty pre-prompt-2.x). Empty array if the claim references no
629	        // proper-noun entities.
630	        proposedEntities: (extracted.proposedEntities ?? []).map((e) => ({
631	          entityType: e.entityType,
632	          rawString: e.rawString,
633	        })),
634	        stance: legacyStanceToCandidateStance(extracted.semanticRole),
635	        // P1 #2 — sensitivityFlags now sourced from the model. Was hardcoded
636	        // false on every claim pre-prompt-2.x, which meant the sensitivity
637	        // gate could never fire in production. Strict-mode definitions live
638	        // in EXTRACTION_SYSTEM_PROMPT.
639	        containsSensitivePersonalData:
640	          extracted.sensitivityFlags?.containsSensitivePersonalData ?? false,
641	        containsSensitiveHRData: extracted.sensitivityFlags?.containsSensitiveHRData ?? false,
642	        isPersonalConflict: extracted.sensitivityFlags?.isPersonalConflict ?? false,
643	        sensitivityReason: extracted.sensitivityFlags?.sensitivityReason ?? null,
644	        requiresReview: extracted.requiresReview,
645	        reviewReason: extracted.requiresReview ? 'extractor requested review' : null,
646	        rawCandidateJson: extracted as unknown as Record<string, unknown>,
647	      })
648	      .returning({ id: extractionCandidates.id });
649	    if (!candidate) {
650	      console.warn('[claim-extraction] candidate insert returned no row — skipping');
651	      continue;
652	    }
653	    outcome.candidatesStaged += 1;
654	
655	    // Insert evidence (single row per candidate for now — the extraction
656	    // schema only emits one quote per claim).
657	    const sourceMsg = segment.find((m) => m.id === extracted.evidence.sourceMessageId);
658	    const sourcePointerCheck = validateSourcePointer({
659	      sourceType: 'message',
660	      sourceMessageId: extracted.evidence.sourceMessageId,
661	    });
662	    if (!sourcePointerCheck.ok || !sourceMsg) {
663	      await db.insert(extractionValidationResults).values({
664	        candidateId: candidate.id,
665	        checkName: sourcePointerCheck.failedCheckName ?? 'source_exists',
666	        status: 'fail',
667	        detail: !sourceMsg
668	          ? `sourceMessageId ${extracted.evidence.sourceMessageId} not in segment`
669	          : sourcePointerCheck.detail,
670	      });
671	      await db
672	        .update(extractionCandidates)
673	        .set({
674	          status: 'validation_failed',
675	          validationError: 'source pointer invalid',
676	          validatedAt: new Date(),
677	        })
678	        .where(eq(extractionCandidates.id, candidate.id));
679	      outcome.rejections += 1;
680	      continue;
681	    }
682	
683	    const [evRow] = await db
684	      .insert(extractionCandidateEvidence)
685	      .values({
686	        candidateId: candidate.id,
687	        sourceType: 'message',
688	        sourceMessageId: extracted.evidence.sourceMessageId,
689	        assertedByEmployeeId:
690	          (segment.find((m) => m.id === extracted.evidence.sourceMessageId) as
691	            | (FormattedMessage & { employeeId?: string })
692	            | undefined)?.employeeId ?? null,
693	        exactQuoteProvided: extracted.evidence.exactQuote,
694	        validationStatus: 'pending',
695	        confidence: extracted.evidence.confidence,
696	      })
697	      .returning({ id: extractionCandidateEvidence.id });
698	    if (!evRow) {
699	      console.warn('[claim-extraction] candidate evidence insert returned no row — skipping');
700	      continue;
701	    }
702	
703	    // R5 — quote validation. Messages (incl. Teams-transcript utterances) get a
704	    // lenient policy: normalize whitespace/quotes, plus a fuzzy fallback that
705	    // tolerates the model paraphrasing disfluent speech while still anchoring
706	    // the evidence to the real utterance. See DECISIONS.md D-transcript-fuzzy-quote.
707	    const quoteRes = validateQuote({
708	      sourceText: sourceMsg.content,
709	      exactQuoteProvided: extracted.evidence.exactQuote,
710	      normalizationPolicy: {
711	        allowCRLF: true,
712	        allowSmartQuotes: true,
713	        allowWhitespaceCollapse: true,
714	        allowLeadingTrailingTrim: true,
715	      },
716	      allowFuzzy: true,
717	    });
718	    await db
719	      .update(extractionCandidateEvidence)
720	      .set({
721	        validationStatus: quoteRes.validationStatus,
722	        validationMethod: quoteRes.validationMethod,
723	        validatedExactQuote: quoteRes.validatedExactQuote ?? null,
724	        validatedCharStart: quoteRes.validatedCharStart ?? null,
725	        validatedCharEnd: quoteRes.validatedCharEnd ?? null,
726	        validatedAt: new Date(),
727	        validationError:
728	          quoteRes.verdict === 'exact_match' || quoteRes.verdict === 'normalized_match'
729	            ? null
730	            : quoteRes.detail,
731	      })
732	      .where(eq(extractionCandidateEvidence.id, evRow.id));
733	    await db.insert(extractionValidationResults).values({
734	      candidateId: candidate.id,
735	      candidateEvidenceId: evRow.id,
736	      checkName: quoteRes.failedCheckName ?? 'quote_exact_match',
737	      status:
738	        quoteRes.verdict === 'exact_match' || quoteRes.verdict === 'normalized_match'
739	          ? 'pass'
740	          : 'fail',
741	      detail: quoteRes.detail,
742	    });
743	
744	    if (quoteRes.verdict !== 'exact_match' && quoteRes.verdict !== 'normalized_match') {
745	      consecutiveQuoteFailureCount += 1;
746	      await db
747	        .update(extractionCandidates)
748	        .set({
749	          status: 'validation_failed',
750	          validationError: quoteRes.detail,
751	          validatedAt: new Date(),
752	        })
753	        .where(eq(extractionCandidates.id, candidate.id));
754	      outcome.rejections += 1;
755	
756	      // Circuit-breaker check after each failure.
757	      const cbDecision = decideCircuitBreaker({
758	        validationAttemptCount,
759	        consecutiveQuoteFailureCount,
760	      });
761	      if (cbDecision.kind === 'trip_breaker') {
762	        await db
763	          .update(extractionBatches)
764	          .set({
765	            status: 'failed_validation_loop',
766	            consecutiveQuoteFailureCount,
767	            validationAttemptCount,
768	            finishedAt: new Date(),
769	          })
770	          .where(eq(extractionBatches.id, batch.id));
771	        await db.insert(extractionValidationResults).values({
772	          candidateId: candidate.id,
773	          checkName: cbDecision.validationResultToWrite.checkName,
774	          status: cbDecision.validationResultToWrite.status,
775	          detail: cbDecision.validationResultToWrite.detail,
776	          metadataJson: {
777	            routeId: route.routeId,
778	            modelRunIdAttempted: modelRunId,
779	            sourceHash,
780	          },
781	        });
782	        outcome.circuitBreakerTripped = true;
783	        break; // stop processing this batch
784	      }
785	      continue;
786	    }
787	
788	    // Quote passed → reset the consecutive failure counter.
789	    consecutiveQuoteFailureCount = 0;
790	
791	    // R5.5 — taxonomy validation. proposedEntities sourced from prompt-2.x
792	    // (P2 #1). The resolver picks up licensor-vs-vendor type mismatches.
793	    const taxRes = validateTaxonomy({
794	      proposedTopDomainIds,
795	      activeTopDomainIds,
796	      proposedEntities: (extracted.proposedEntities ?? []).map((e) => ({
797	        entityType: e.entityType as EntityType,
798	        rawString: e.rawString,
799	      })),
800	      entityRegistry,
801	    });
802	    await db.insert(extractionValidationResults).values({
803	      candidateId: candidate.id,
804	      checkName: 'domain_valid',
805	      status: taxRes.ok ? 'pass' : 'fail',
806	      detail: taxRes.ok
807	        ? `Top-domains validated: ${taxRes.validTopDomainIds.join(', ')}`
808	        : taxRes.failures.map((f) => f.detail).join('; '),
809	    });
810	
811	    // Regardless of overall taxRes.ok, stage any entity proposals so admin
812	    // can review unknown entities or type-mismatch corrections.
813	    // stageEntityProposal() uses pg_trgm fuzzy-dedup: near-duplicate surfaces
814	    // (similarity >= 0.85) increment proposal_count instead of creating new rows.
815	    for (const p of taxRes.entityProposalsToCreate) {
816	      await stageEntityProposal(db, {
817	        proposedEntityType: p.proposedEntityType,
818	        proposedCanonicalValue: p.proposedCanonicalValue,
819	        rawString: p.rawString,
820	        observedInSourceType: 'claim_candidate',
821	        observedInSourceId: candidate.id,
822	        proposedByModelRunId: modelRunId,
823	      });
824	    }
825	
826	    if (!taxRes.ok) {
827	      await db
828	        .update(extractionCandidates)
829	        .set({
830	          status: 'validation_failed',
831	          validationError: taxRes.failureSummary ?? 'taxonomy invalid',
832	          validatedAt: new Date(),
833	        })
834	        .where(eq(extractionCandidates.id, candidate.id));
835	      outcome.rejections += 1;
836	      continue;
837	    }
838	
839	    // P1 #2 — Sensitivity gate. If the model flagged any sensitivity, the
840	    // candidate is quarantined here and never reaches promotion. The
841	    // candidate row is preserved with the model's reason so admin can
842	    // review it via /admin/ai/candidates → "Sensitive" tab.
843	    const sensitivityFired =
844	      extracted.sensitivityFlags?.containsSensitiveHRData === true ||
845	      extracted.sensitivityFlags?.containsSensitivePersonalData === true ||
846	      extracted.sensitivityFlags?.isPersonalConflict === true;
847	    if (sensitivityFired) {
848	      await db.insert(extractionValidationResults).values({
849	        candidateId: candidate.id,
850	        checkName: 'sensitivity_gate',
851	        status: 'fail',
852	        detail: extracted.sensitivityFlags?.sensitivityReason ?? 'extractor flagged sensitive content',
853	        metadataJson: {
854	          containsSensitiveHRData: extracted.sensitivityFlags?.containsSensitiveHRData ?? false,
855	          containsSensitivePersonalData:
856	            extracted.sensitivityFlags?.containsSensitivePersonalData ?? false,
857	          isPersonalConflict: extracted.sensitivityFlags?.isPersonalConflict ?? false,
858	        },
859	      });
860	      await db
861	        .update(extractionCandidates)
862	        .set({
863	          status: 'quarantined_sensitive',
864	          validationError: extracted.sensitivityFlags?.sensitivityReason ?? 'sensitive content flagged by extractor',
865	          validatedAt: new Date(),
866	        })
867	        .where(eq(extractionCandidates.id, candidate.id));
868	      outcome.rejections += 1;
869	      continue;
870	    }
871	
872	    // Sensitivity gate passed → record the pass row for the audit trail.
873	    await db.insert(extractionValidationResults).values({
874	      candidateId: candidate.id,
875	      checkName: 'sensitivity_gate',
876	      status: 'pass',
877	      detail: 'extractor reported no sensitive content',
878	    });
879	
880	    // Mark candidate validated; the executor re-reads it inside the lock.
881	    await db
882	      .update(extractionCandidates)
883	      .set({ status: 'validated', validatedAt: new Date() })
884	      .where(eq(extractionCandidates.id, candidate.id));
885	
886	    const validatedQuote = quoteRes.validatedExactQuote ?? extracted.evidence.exactQuote;
887	    const candidateHash = computeCandidateHash({
888	      summary: extracted.summary,
889	      topDomainIds: taxRes.validTopDomainIds,
890	      validatedQuotes: [validatedQuote],
891	      sourcePointers: [`message:${extracted.evidence.sourceMessageId}`],
892	    });
893	
894	    // executePromotion re-reads the candidate row + validated evidence
895	    // INSIDE the advisory lock. We pass only the auxiliary inputs that
896	    // can't be reconstructed from candidate-table state: taxonomy
897	    // validation result (depends on the live entities/top-domains
898	    // registries) and metadata (caller-computed per call).
899	    try {
900	      const result = await executePromotion({
901	        db,
902	        candidateId: candidate.id,
903	        candidateHash,
904	        auxiliaryInputs: { taxonomy: taxRes },
905	        modelRunId: modelRunId ?? undefined,
906	      });
907	      if (result.outcome === 'inserted_new_claim') outcome.claimsPromoted += 1;
908	      else if (result.outcome === 'appended_to_existing_claim') outcome.duplicatesAppended += 1;
909	      else outcome.rejections += 1;
910	    } catch (promErr) {
911	      if (promErr instanceof AdvisoryLockBusyError) {
912	        // Skip — another worker has the lock. Candidate stays 'validated';
913	        // the next cron run will pick it up.
914	        await db.insert(extractionValidationResults).values({
915	          candidateId: candidate.id,
916	          checkName: 'duplicate_promotion_lock',
917	          status: 'skipped',
918	          detail: 'Advisory lock busy; another worker holds it.',
919	        });
920	      } else {
921	        await db.insert(extractionValidationResults).values({
922	          candidateId: candidate.id,
923	          checkName: 'promotion_transaction',
924	          status: 'fail',
925	          detail: promErr instanceof Error ? promErr.message : String(promErr),
926	        });
927	        outcome.rejections += 1;
928	      }
929	    }
930	  } // end claims loop
931	
932	  if (!outcome.circuitBreakerTripped) {
933	    await db
934	      .update(extractionBatches)
935	      .set({
936	        status: 'validation_complete',
937	        consecutiveQuoteFailureCount,
938	        validationAttemptCount,
939	        finishedAt: new Date(),
940	      })
941	      .where(eq(extractionBatches.id, batch.id));
942	  }
943	
944	  // Mark messages complete. Even when individual candidates failed, the
945	  // segment itself was processed; failed candidates are kept staged for
946	  // admin review separately.
947	  await db
948	    .update(messages)
949	    .set({ extractionStatus: 'complete', extractedAt: new Date() })
950	    .where(inArray(messages.id, segmentIds));
951	  outcome.messagesProcessed = segmentIds.length;
952	
953	  return outcome;
954	}
