959	
960	export async function resolveExtractionRoute(db: OracleDb): Promise<OracleModelRoute> {
961	  // Reads both default_extraction_route + default_extraction_reasoning_effort.
962	  const resolved = await resolveRouteFromSettings(db, 'extraction');
963	  if (resolved) return resolved;
964	  const fallback = getOracleRoute(FALLBACK_ROUTE_ID);
965	  if (!fallback) {
966	    throw new Error(
967	      `[claim-extraction] default_extraction_route unset/unresolvable and fallback "${FALLBACK_ROUTE_ID}" missing.`,
968	    );
969	  }
970	  console.warn(
971	    `[claim-extraction] default_extraction_route unset/unresolvable; using fallback "${FALLBACK_ROUTE_ID}".`,
972	  );
973	  return fallback;
974	}
975	
976	export async function loadActiveTopDomainIds(db: OracleDb): Promise<string[]> {
977	  const rows = await db.execute<{ id: string }>(
978	    sql`SELECT id FROM knowledge_top_domains WHERE is_active = true`,
979	  );
980	  // postgres-js result shape variance — handle both.
981	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
982	  const list: Array<{ id: string }> = (rows as any).rows ?? (rows as any);
983	  return list.map((r) => r.id);
984	}
985	
986	/**
987	 * Load the entity registry slice used by R5.5 validateTaxonomy. For round 1
988	 * we load all rows (the seed is ~56 rows) — when the registry grows past a
989	 * few hundred, scope to (proposed types ∪ canonical match of raw strings).
990	 */
991	export async function loadEntityRegistry(db: OracleDb): Promise<RegistryEntity[]> {
992	  const rows = await db
993	    .select({
994	      id: entities.id,
995	      entityType: entities.entityType,
996	      canonicalValue: entities.canonicalValue,
997	      aliases: entities.aliases,
998	    })
999	    .from(entities);
1000	  return rows.map((r) => ({
1001	    id: r.id,
1002	    entityType: r.entityType as EntityType,
1003	    canonicalValue: r.canonicalValue,
1004	    aliases: (r.aliases as string[] | null) ?? null,
1005	  }));
1006	}
1007	
1008	export function groupIntoSegments(
1009	  pendingMessages: Array<{
1010	    id: string;
1011	    channelId: string;
1012	    employeeId: string | null;
1013	    role: 'user' | 'assistant' | 'system' | string;
1014	    content: string;
1015	    createdAt: Date;
1016	    authorName: string | null;
1017	  }>,
1018	): FormattedMessage[][] {
1019	  const byChannel = new Map<string, typeof pendingMessages>();
1020	  for (const m of pendingMessages) {
1021	    const list = byChannel.get(m.channelId) ?? [];
1022	    list.push(m);
1023	    byChannel.set(m.channelId, list);
1024	  }
1025	
1026	  const allSegments: FormattedMessage[][] = [];
1027	
1028	  for (const [_channelId, channelMessages] of byChannel) {
1029	    channelMessages.sort(
1030	      (a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime(),
1031	    );
1032	    const segments: FormattedMessage[][] = [];
1033	    let current: FormattedMessage[] = [];
1034	
1035	    for (const m of channelMessages) {
1036	      if (current.length > 0) {
1037	        const last = current[current.length - 1]!;
1038	        const gap = new Date(m.createdAt).getTime() - new Date(last.createdAt).getTime();
1039	        if (gap > SEGMENT_GAP_MS) {
1040	          segments.push(current);
1041	          current = [];
1042	        }
1043	      }
1044	      current.push({
1045	        id: m.id,
1046	        role: m.role as 'user' | 'assistant' | 'system',
1047	        content: m.content,
1048	        authorName: m.authorName ?? null,
1049	        createdAt: new Date(m.createdAt),
1050	      });
1051	    }
1052	    if (current.length > 0) segments.push(current);
1053	    allSegments.push(...segments);
1054	  }
1055	
1056	  return allSegments;
1057	}
