1517	/**
1518	 * Choose the document chunk to attach as the evidence pointer for a quote.
1519	 *
1520	 * Searches the full rawText first, then maps the match offset into the current
1521	 * extraction window. This catches quotes that straddle chunk-overlap boundaries
1522	 * better than checking each chunk's text independently.
1523	 */
1524	function pickEvidenceChunk<TChunk extends InsertedDocumentChunk>(
1525	  rawText: string,
1526	  exactQuote: string,
1527	  chunks: TChunk[],
1528	  sourceIdFallback?: TChunk,
1529	): TChunk {
1530	  const fallback = sourceIdFallback ?? chunks[0]!;
1531	  if (!exactQuote) return fallback;
1532	
1533	  let matchOffset = rawText.indexOf(exactQuote);
1534	  if (matchOffset < 0) {
1535	    const collapsedRaw = rawText.replace(/\s+/g, ' ');
1536	    const collapsedQuote = exactQuote.replace(/\s+/g, ' ').trim();
1537	    const collapsedIdx = collapsedQuote ? collapsedRaw.indexOf(collapsedQuote) : -1;
1538	    if (collapsedIdx < 0) return fallback;
1539	    let consumed = 0;
1540	    for (let i = 0; i < rawText.length; i++) {
1541	      if (consumed >= collapsedIdx) {
1542	        matchOffset = i;
1543	        break;
1544	      }
1545	      if (/\s/.test(rawText[i]!)) {
1546	        if (i === 0 || !/\s/.test(rawText[i - 1]!)) consumed += 1;
1547	      } else {
1548	        consumed += 1;
1549	      }
1550	    }
1551	    if (matchOffset < 0) return fallback;
1552	  }
1553	
1554	  const covering = chunks.find((c) => matchOffset >= c.start && matchOffset < c.end);
1555	  return covering ?? fallback;
1556	}
